class MyApp extends StatefulWidget {
  @override
  _MyAppState createState() => _MyAppState();
}

class _MyAppState extends State<MyApp> {
  final GlobalKey<NavigatorState> navigatorKey = GlobalKey<NavigatorState>();
  StreamSubscription? _linkSubscription;

  @override
  void initState() {
    super.initState();
    _initDeepLinks();
  }

  Future<void> _initDeepLinks() async {
    await _handleInitialLink();
    _handleIncomingLinks();
  }

  Future<void> _handleInitialLink() async {
    try {
      final initialLink = await getInitialLink();
      if (initialLink != null) {
        _processDeepLink(initialLink);
      }
    } on PlatformException {
      // Handle exception
    }
  }

  void _handleIncomingLinks() {
    _linkSubscription = linkStream.listen((String? link) {
      if (link != null) {
        _processDeepLink(link);
      }
    }, onError: (err) {
      // Handle error
    });
  }

  void _processDeepLink(String link) {
    final uri = Uri.parse(link);
    
    if (uri.scheme == 'myapp') {
      final pathSegments = uri.pathSegments;
      final queryParams = uri.queryParameters;
      
      if (pathSegments.isEmpty) {
        _navigateToHome();
        return;
      }

      final route = pathSegments[0];
      
      switch (route) {
        case 'profile':
          if (pathSegments.length > 1) {
            final userId = pathSegments[1];
            _navigateToProfile(userId, queryParams);
          }
          break;
        case 'payment':
          if (pathSegments.length > 1 && pathSegments[1] == 'confirm') {
            _navigateToPaymentConfirm(queryParams);
          }
          break;
        case 'product':
          if (pathSegments.length > 1) {
            final productId = pathSegments[1];
            _navigateToProduct(productId, queryParams);
          }
          break;
        case 'settings':
          _navigateToSettings(queryParams);
          break;
        default:
          _navigateToHome();
      }
    }
  }

  void _navigateToHome() {
    navigatorKey.currentState?.pushAndRemoveUntil(
      MaterialPageRoute(builder: (context) => HomeScreen()),
      (route) => false,
    );
  }

  void _navigateToProfile(String userId, Map<String, String> params) {
    navigatorKey.currentState?.push(
      MaterialPageRoute(
        builder: (context) => ProfileScreen(
          userId: userId,
          params: params,
        ),
      ),
    );
  }

  void _navigateToPaymentConfirm(Map<String, String> params) {
    navigatorKey.currentState?.push(
      MaterialPageRoute(
        builder: (context) => PaymentConfirmScreen(
          params: params,
        ),
      ),
    );
  }

  void _navigateToProduct(String productId, Map<String, String> params) {
    navigatorKey.currentState?.push(
      MaterialPageRoute(
        builder: (context) => ProductScreen(
          productId: productId,
          params: params,
        ),
      ),
    );
  }

  void _navigateToSettings(Map<String, String> params) {
    navigatorKey.currentState?.push(
      MaterialPageRoute(
        builder: (context) => SettingsScreen(
          params: params,
        ),
      ),
    );
  }

  @override
  void dispose() {
    _linkSubscription?.cancel();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      navigatorKey: navigatorKey,
      title: 'Deep Link Handler',
      theme: ThemeData(
        primarySwatch: Colors.blue,
      ),
      home: HomeScreen(),
    );
  }
}

